CREATE TABLE offer_tasks (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,

  -- Task status and progress
  status TEXT NOT NULL CHECK(status IN ('pending', 'running', 'completed', 'failed')) DEFAULT 'pending',
  stage TEXT,
  progress INTEGER DEFAULT 0 CHECK(progress >= 0 AND progress <= 100),
  message TEXT,

  -- Input parameters
  affiliate_link TEXT NOT NULL,
  target_country TEXT NOT NULL,
  page_type TEXT,
  store_product_links TEXT,
  skip_cache INTEGER DEFAULT 0,
  skip_warmup INTEGER DEFAULT 0,
  product_price TEXT,
  commission_payout TEXT,

  -- Task relationships
  batch_id TEXT,
  offer_id INTEGER,

  -- Output results
  result TEXT,
  error TEXT,

  -- Timestamps
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  started_at TEXT,
  completed_at TEXT, brand_name TEXT,

  -- Foreign keys
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (batch_id) REFERENCES batch_tasks(id) ON DELETE SET NULL,
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE SET NULL
);
CREATE TABLE creative_tasks (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,
  offer_id INTEGER NOT NULL,

  
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending', 'running', 'completed', 'failed')),
  stage TEXT DEFAULT 'init',  
  progress INTEGER DEFAULT 0,  
  message TEXT,

  
  max_retries INTEGER DEFAULT 3,
  target_rating TEXT DEFAULT 'EXCELLENT',

  
  current_attempt INTEGER DEFAULT 0,
  optimization_history TEXT,  

  
  creative_id INTEGER,  
  result TEXT,  
  error TEXT,   

  
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  started_at TEXT,
  completed_at TEXT,
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),

  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE,
  FOREIGN KEY (creative_id) REFERENCES ad_creatives(id) ON DELETE SET NULL
);
CREATE TABLE audit_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER,
  event_type TEXT NOT NULL,
  ip_address TEXT NOT NULL,
  user_agent TEXT NOT NULL,
  details TEXT, 
  created_at TEXT NOT NULL DEFAULT (datetime('now')), operator_id INTEGER REFERENCES users(id) ON DELETE SET NULL, operator_username TEXT, target_user_id INTEGER REFERENCES users(id) ON DELETE SET NULL, target_username TEXT, status TEXT DEFAULT 'success' CHECK (status IN ('success', 'failure')), error_message TEXT,

  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL
);
CREATE TABLE offer_keyword_pools (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  offer_id INTEGER NOT NULL,
  user_id INTEGER NOT NULL,

  
  brand_keywords TEXT NOT NULL DEFAULT '[]',  

  
  bucket_a_keywords TEXT NOT NULL DEFAULT '[]',  
  bucket_b_keywords TEXT NOT NULL DEFAULT '[]',  
  bucket_c_keywords TEXT NOT NULL DEFAULT '[]',  

  
  bucket_a_intent TEXT DEFAULT '品牌商品锚点',
  bucket_b_intent TEXT DEFAULT '商品需求场景',
  bucket_c_intent TEXT DEFAULT '功能规格特性',

  
  total_keywords INTEGER NOT NULL DEFAULT 0,
  clustering_model TEXT,  
  clustering_prompt_version TEXT,  
  balance_score REAL,  

  
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')), bucket_d_keywords TEXT DEFAULT '[]', bucket_d_intent TEXT DEFAULT '商品需求扩展', store_bucket_a_keywords TEXT DEFAULT '[]', store_bucket_b_keywords TEXT DEFAULT '[]', store_bucket_c_keywords TEXT DEFAULT '[]', store_bucket_d_keywords TEXT DEFAULT '[]', store_bucket_s_keywords TEXT DEFAULT '[]', store_bucket_a_intent TEXT DEFAULT '品牌商品集合', store_bucket_b_intent TEXT DEFAULT '商品需求场景', store_bucket_c_intent TEXT DEFAULT '热门商品线', store_bucket_d_intent TEXT DEFAULT '信任服务信号', store_bucket_s_intent TEXT DEFAULT '店铺全量覆盖', link_type TEXT DEFAULT 'product',

  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "global_keywords" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  keyword TEXT NOT NULL,
  country TEXT NOT NULL DEFAULT 'US',
  language TEXT NOT NULL DEFAULT 'en',
  search_volume INTEGER DEFAULT 0,
  competition_level TEXT,
  avg_cpc_micros INTEGER,
  cached_at TEXT DEFAULT (datetime('now')),
  created_at TEXT DEFAULT (datetime('now')),
  UNIQUE(keyword, country, language)
);
CREATE TABLE IF NOT EXISTS "ad_creatives" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  offer_id INTEGER NOT NULL,
  user_id INTEGER NOT NULL,
  headlines TEXT NOT NULL,
  descriptions TEXT NOT NULL,
  callouts TEXT,
  sitelinks TEXT,
  keywords TEXT,
  keywords_with_volume TEXT DEFAULT NULL,
  negative_keywords TEXT DEFAULT NULL,
  negative_keywords_match_type TEXT DEFAULT '{}',
  final_url TEXT NOT NULL,
  final_url_suffix TEXT,
  theme TEXT,
  explanation TEXT DEFAULT NULL,
  score REAL,
  score_breakdown TEXT,
  generation_round INTEGER DEFAULT 1,
  ai_model TEXT,
  is_selected INTEGER DEFAULT 0,
  google_campaign_id TEXT,
  industry_code TEXT,
  orientation TEXT,
  brand TEXT,
  url TEXT,
  score_explanation TEXT,
  ad_strength TEXT DEFAULT 'UNKNOWN',
  ab_test_variant_id INTEGER,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  
  launch_score INTEGER DEFAULT NULL,
  
  ad_group_id INTEGER DEFAULT NULL,
  ad_id TEXT DEFAULT NULL,
  creation_status TEXT NOT NULL DEFAULT 'draft',
  creation_error TEXT DEFAULT NULL,
  last_sync_at TEXT DEFAULT NULL,
  ad_strength_data TEXT DEFAULT NULL,
  path1 TEXT DEFAULT NULL,
  path2 TEXT DEFAULT NULL,
  creative_type TEXT DEFAULT NULL,
  keyword_bucket TEXT CHECK(keyword_bucket IN ('A', 'B', 'C', 'D', 'S')),
  keyword_pool_id INTEGER REFERENCES offer_keyword_pools(id),
  bucket_intent TEXT, is_deleted INTEGER NOT NULL DEFAULT 0, deleted_at TIMESTAMP NULL,
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "batch_tasks" (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,

  
  task_type TEXT NOT NULL CHECK(task_type IN ('offer-creation', 'offer-scrape', 'offer-enhance')) DEFAULT 'offer-creation',
  status TEXT NOT NULL CHECK(status IN ('pending', 'running', 'completed', 'failed', 'partial', 'cancelled')) DEFAULT 'pending',

  
  total_count INTEGER DEFAULT 0 CHECK(total_count >= 0),
  completed_count INTEGER DEFAULT 0 CHECK(completed_count >= 0),
  failed_count INTEGER DEFAULT 0 CHECK(failed_count >= 0),

  
  source_file TEXT,
  metadata TEXT,

  
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  started_at TEXT,
  completed_at TEXT,

  
  cancelled_at TEXT,
  cancelled_by INTEGER,
  cancellation_reason TEXT,

  
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (cancelled_by) REFERENCES users(id) ON DELETE SET NULL
);
CREATE TABLE IF NOT EXISTS "upload_records" (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,
  batch_id TEXT NOT NULL,

  
  file_name TEXT NOT NULL,
  file_size INTEGER NOT NULL,

  
  valid_count INTEGER DEFAULT 0,
  processed_count INTEGER DEFAULT 0,
  skipped_count INTEGER DEFAULT 0,
  failed_count INTEGER DEFAULT 0,
  success_rate REAL DEFAULT 0.0,

  
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending', 'processing', 'completed', 'failed', 'partial', 'cancelled')),

  
  metadata TEXT,

  
  uploaded_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  completed_at TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,

  
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (batch_id) REFERENCES batch_tasks(id) ON DELETE CASCADE
);
CREATE TABLE google_ads_service_accounts (
  id TEXT PRIMARY KEY,
  user_id INTEGER NOT NULL,
  name TEXT NOT NULL,
  mcc_customer_id TEXT NOT NULL,
  developer_token TEXT NOT NULL,
  service_account_email TEXT NOT NULL,
  private_key TEXT NOT NULL,
  project_id TEXT,
  is_active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE campaigns (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  offer_id INTEGER NOT NULL,
  google_ads_account_id INTEGER,
  campaign_id TEXT UNIQUE,
  campaign_name TEXT NOT NULL,
  budget_amount REAL NOT NULL,
  budget_type TEXT NOT NULL DEFAULT 'DAILY',
  target_cpa REAL,
  max_cpc REAL,
  status TEXT NOT NULL DEFAULT 'PAUSED',
  start_date TIMESTAMP,
  end_date TIMESTAMP,
  creation_status TEXT NOT NULL DEFAULT 'draft',
  creation_error TEXT,
  last_sync_at TIMESTAMP,
  ad_creative_id INTEGER REFERENCES ad_creatives(id) ON DELETE SET NULL,
  google_campaign_id TEXT,
  google_ad_group_id TEXT,
  google_ad_id TEXT,
  campaign_config TEXT,
  pause_old_campaigns BOOLEAN,
  is_test_variant BOOLEAN DEFAULT FALSE,
  ab_test_id INTEGER,
  traffic_allocation REAL DEFAULT 1.0 CHECK (traffic_allocation >= 0 AND traffic_allocation <= 1),
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, is_deleted INTEGER NOT NULL DEFAULT 0, deleted_at TIMESTAMP NULL, is_active INTEGER DEFAULT 1, published_at TEXT,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE,
  FOREIGN KEY (google_ads_account_id) REFERENCES google_ads_accounts(id) ON DELETE SET NULL
);
CREATE TABLE weekly_recommendations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  google_ads_account_id INTEGER,
  recommendation_type TEXT NOT NULL,
  recommendation_data TEXT NOT NULL,
  priority TEXT NOT NULL DEFAULT 'MEDIUM',
  status TEXT NOT NULL DEFAULT 'pending',
  applied_at TIMESTAMP,
  week_start_date TIMESTAMP NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (google_ads_account_id) REFERENCES google_ads_accounts(id) ON DELETE SET NULL
);
CREATE TABLE optimization_recommendations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  google_ads_account_id INTEGER,
  recommendation_id TEXT NOT NULL UNIQUE,
  recommendation_type TEXT NOT NULL,
  impact TEXT,
  recommendation_data TEXT NOT NULL,
  status TEXT DEFAULT 'pending',
  applied_at TIMESTAMP,
  dismissed_at TIMESTAMP,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (google_ads_account_id) REFERENCES google_ads_accounts(id) ON DELETE SET NULL
);
CREATE TABLE sync_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  google_ads_account_id INTEGER,
  sync_type TEXT NOT NULL,
  status TEXT NOT NULL,
  record_count INTEGER NOT NULL DEFAULT 0,
  duration_ms INTEGER NOT NULL DEFAULT 0,
  error_message TEXT,
  started_at TIMESTAMP NOT NULL,
  completed_at TIMESTAMP,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (google_ads_account_id) REFERENCES google_ads_accounts(id) ON DELETE SET NULL
);
CREATE TABLE offer_blacklist (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  brand TEXT NOT NULL,
  target_country TEXT NOT NULL,
  offer_id INTEGER NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE,
  UNIQUE(user_id, brand, target_country)
);
CREATE TABLE user_sessions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  session_token TEXT UNIQUE NOT NULL,
  ip_address TEXT NOT NULL,
  user_agent TEXT NOT NULL,
  device_fingerprint TEXT NOT NULL,
  is_current INTEGER DEFAULT 1,
  is_suspicious INTEGER DEFAULT 0,
  suspicious_reason TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  last_activity_at TEXT NOT NULL DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL,
  revoked_at TEXT,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE account_sharing_alerts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  alert_type TEXT NOT NULL,
  severity TEXT NOT NULL DEFAULT 'warning',
  description TEXT NOT NULL,
  ip_addresses TEXT,
  device_fingerprints TEXT,
  metadata TEXT,
  is_resolved INTEGER DEFAULT 0,
  resolved_at TEXT,
  resolved_by INTEGER,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (resolved_by) REFERENCES users(id)
);
CREATE TABLE trusted_devices (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  device_fingerprint TEXT NOT NULL,
  device_name TEXT,
  last_used_at TEXT NOT NULL DEFAULT (datetime('now')),
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  is_active INTEGER DEFAULT 1,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  UNIQUE(user_id, device_fingerprint)
);
CREATE TABLE click_farm_tasks (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,
  offer_id INTEGER NOT NULL,

  daily_click_count INTEGER NOT NULL DEFAULT 216,
  start_time TEXT NOT NULL DEFAULT '06:00',
  end_time TEXT NOT NULL DEFAULT '24:00',
  duration_days INTEGER NOT NULL DEFAULT 7,
  hourly_distribution TEXT NOT NULL,

  scheduled_start_date TEXT DEFAULT (DATE('now')),

  status TEXT NOT NULL DEFAULT 'pending',
  pause_reason TEXT,
  pause_message TEXT,
  paused_at TEXT,

  progress INTEGER DEFAULT 0,
  total_clicks INTEGER DEFAULT 0,
  success_clicks INTEGER DEFAULT 0,
  failed_clicks INTEGER DEFAULT 0,

  daily_history TEXT DEFAULT '[]',

  timezone TEXT NOT NULL DEFAULT 'America/New_York',

  is_deleted INTEGER DEFAULT 0,
  deleted_at TEXT,

  started_at TEXT,
  completed_at TEXT,
  next_run_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),

  referer_config TEXT DEFAULT NULL,

  
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "risk_alerts" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL,
  alert_type TEXT,
  severity TEXT NOT NULL,
  title TEXT NOT NULL,
  message TEXT NOT NULL,
  related_type TEXT,
  related_id INTEGER,
  related_name TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  resolved_at TEXT,
  resolved_by INTEGER,
  detected_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  resource_type TEXT,
  resource_id INTEGER,
  details TEXT,
  acknowledged_at TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  FOREIGN KEY (resolved_by) REFERENCES users(id)
);
CREATE TABLE IF NOT EXISTS "url_swap_tasks" (

  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  user_id INTEGER NOT NULL,
  offer_id INTEGER NOT NULL,


  swap_interval_minutes INTEGER NOT NULL DEFAULT 5,
  enabled BOOLEAN DEFAULT TRUE,
  duration_days INTEGER NOT NULL DEFAULT 7,


  swap_mode TEXT NOT NULL DEFAULT 'auto',
  manual_final_url_suffixes TEXT NOT NULL DEFAULT '[]',
  manual_suffix_cursor INTEGER NOT NULL DEFAULT 0,


  google_customer_id TEXT,
  google_campaign_id TEXT,


  current_final_url TEXT,
  current_final_url_suffix TEXT,


  progress INTEGER DEFAULT 0,
  total_swaps INTEGER DEFAULT 0,
  success_swaps INTEGER DEFAULT 0,
  failed_swaps INTEGER DEFAULT 0,
  url_changed_count INTEGER DEFAULT 0,

  
  swap_history TEXT DEFAULT '[]',

  
  status TEXT NOT NULL DEFAULT 'enabled',
  error_message TEXT,
  error_at TEXT,

  
  started_at TEXT,
  completed_at TEXT,
  next_swap_at TEXT,

  
  is_deleted INTEGER DEFAULT 0,
  deleted_at TEXT,

  
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),

  
  consecutive_failures INTEGER DEFAULT 0,

  
  FOREIGN KEY (offer_id) REFERENCES offers(id) ON DELETE CASCADE
);
CREATE TABLE google_ads_test_credentials (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER NOT NULL UNIQUE,
  client_id TEXT NOT NULL,
  client_secret TEXT NOT NULL,
  refresh_token TEXT NOT NULL,
  access_token TEXT,
  developer_token TEXT NOT NULL,
  login_customer_id TEXT,
  access_token_expires_at TEXT,
  is_active INTEGER DEFAULT 1,
  last_verified_at TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
